import{_ as o,y as a,a as r,o as s,a2 as n,D as i}from"./chunks/framework.DCcmcJcL.js";const h=JSON.parse('{"title":"B2B eCommerce Platform","description":"","frontmatter":{},"headers":[],"relativePath":"b2b-ecommerce-platform/introduction.md","filePath":"b2b-ecommerce-platform/introduction.md","lastUpdated":1782311298000}'),l={name:"b2b-ecommerce-platform/introduction.md"};function m(c,e,p,d,u,g){const t=a("ImagePopup");return s(),r("div",null,[e[0]||(e[0]=n('<h1 id="b2b-ecommerce-platform" tabindex="-1">B2B eCommerce Platform <a class="header-anchor" href="#b2b-ecommerce-platform" aria-label="Permalink to &quot;B2B eCommerce Platform&quot;">​</a></h1><p>The <a href="https://bagisto.com/en/b2b-commerce-platform/" target="_blank" rel="noreferrer">B2B eCommerce Platform</a> is an open-source solution that brings advanced Business-to-Business capabilities to the Bagisto eCommerce platform. It enables companies to manage corporate accounts, bulk orders, and team access from one place, with ease.</p><p>Built to streamline B2B operations, it allows businesses to register their company, manage multiple users, and handle the entire purchasing process from a single, unified dashboard.</p><p>Powerful tools such as Quick Order, Requisition Lists, and Request for Quote (RFQ) make buying faster, simpler, and better organized for business customers, even across large or repeat orders.</p><p>With role-based permissions, companies can assign roles and control exactly what each user can access, ensuring a secure, transparent, and well-managed workflow across the entire team.</p><p>The platform also gives administrators fine-grained control over each company&#39;s experience through <strong>Company Catalogs</strong> (per-company product and category visibility with custom and quantity-tier pricing), <strong>Company Credit</strong> (a buy-now-pay-later account with an audited ledger and a <em>Pay By Credit</em> checkout method), <strong>Sales Representatives</strong> (assign admin users to manage specific companies and their negotiations), and <strong>Company Attributes</strong> (extend the company profile with custom fields).</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Company Registration &amp; Approval</strong> – Storefront company sign-up with optional admin approval before activation.</li><li><strong>Role Based Permissions</strong> – Custom company roles and granular access control for company users.</li><li><strong>Company User Management</strong> – Add company users directly or invite existing store customers to join.</li><li><strong>Requisition Lists, Quick Order &amp; Request for Quote</strong> – Faster, better-organized bulk and repeat purchasing.</li><li><strong>Quotation Handling</strong> – End-to-end buyer–seller negotiation on both the storefront and admin.</li><li><strong>Purchase Orders</strong> – Track and manage procurement across the company.</li><li><strong>Company Catalogs</strong> – Per-company product and category visibility with custom and tier pricing.</li><li><strong>Company Credit (Pay By Credit)</strong> – Per-company credit limits with an audited ledger and reimbursements.</li><li><strong>Sales Representatives</strong> – Assign admin users to manage specific companies.</li><li><strong>Company Attributes</strong> – Custom fields on the company profile.</li><li><strong>Localization &amp; RTL</strong> – Full right-to-left support and translations for all 22 supported locales.</li></ul><p>This makes the B2B eCommerce Platform an ideal fit for wholesalers, manufacturers, and distributors looking to run a scalable, flexible, and efficient online store tailored to business buyers.</p>',9)),i(t,{src:"/images/b2b-ecommerce-platform/intro-banner.webp",alt:"B2B eCommerce Platform"})])}const b=o(l,[["render",m]]);export{h as __pageData,b as default};
